        ];
        list($signed_invoice_string, $invoice_hash, $qr) = $this->signInvoice($invoice, $egs, $token->binary_security_token, $token->private_key);
        $api = new ZatcaApiController();
        $response = $api->reportingInvoiceApi($token->binary_security_token, $token->secret, $invoice_hash, $token->uuid, $signed_invoice_string);
        dd(json_decode($response));
    }

